+        var skip_count: usize = 0;
+        while (lines.next()) |line| {
+            skip_count += 1;
+            if (std.mem.indexOf(u8, line, "const __name__") != null) {
+                // Skip this line and the blank line after
+                _ = lines.next(); // blank line
+                skip_count += 1;
+                break;
+            }
+        }
